import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;

public class LockByKey implements Lock {
    // Map to store locks for each key
    private final ConcurrentHashMap<String, ReentrantLock> lockMap = new ConcurrentHashMap<>();

    @Override
    public void lock(@NonNull String key) {
        // Get or create a lock for the key
        ReentrantLock lock = lockMap.computeIfAbsent(key, k -> new ReentrantLock());
        lock.lock(); // Acquire the lock
    }

    @Override
    public void unlock(@NonNull String key) {
        // Get the lock associated with the key
        ReentrantLock lock = lockMap.get(key);

        if (lock == null) {
            throw new IllegalStateException("Attempting to unlock a key that is not locked: " + key);
        }

        // Check if the current thread holds the lock
        if (!lock.isHeldByCurrentThread()) {
            throw new IllegalStateException("Attempting to unlock a key locked by another thread: " + key);
        }

        lock.unlock(); // Release the lock

        // Remove the lock from the map if it's no longer held by any thread
        if (!lock.isLocked()) {
            lockMap.remove(key, lock);
        }
