import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.preauth.AbstractPreAuthenticatedProcessingFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

public class GraphQLHeaderValidationFilter extends AbstractPreAuthenticatedProcessingFilter {

    @Override
    protected Object getPreAuthenticatedPrincipal(HttpServletRequest request) {
        // Extract the userId header
        String userId = request.getHeader("userId");
        return userId;
    }

    @Override
    protected Object getPreAuthenticatedCredentials(HttpServletRequest request) {
        return null; // No credentials needed for this filter
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain chain)
            throws IOException, ServletException {
        String graphqlQuery = request.getReader().lines().reduce("", String::concat);

        // Check if the query is for signIn or signUp
        if (graphqlQuery.contains("signIn") || graphqlQuery.contains("signUp")) {
            // Skip validation for signIn and signUp
            chain.doFilter(request, response);
            return;
