#include <windows.h> // For LoadLibrary and GetProcAddress
#include <iostream>

// Define a function pointer type for the unmanaged DLL function
typedef bool (*UserLoginFunc)(int id, const wchar_t* username, const wchar_t* password);

// JNI function implementation
JNIEXPORT jboolean JNICALL Java_NativeClassWrapper_userLogin
  (JNIEnv *env, jobject obj, jint id, jcharArray username, jcharArray password) {

    // Convert jcharArray (Java char[]) to wchar_t* (C wide string)
    jsize usernameLength = env->GetArrayLength(username);
    jsize passwordLength = env->GetArrayLength(password);

    wchar_t* nativeUsername = new wchar_t[usernameLength + 1];
    wchar_t* nativePassword = new wchar_t[passwordLength + 1];

    env->GetCharArrayRegion(username, 0, usernameLength, (jchar*)nativeUsername);
    env->GetCharArrayRegion(password, 0, passwordLength, (jchar*)nativePassword);

    nativeUsername[usernameLength] = L'\0'; // Null-terminate the string
    nativePassword[passwordLength] = L'\0'; // Null-terminate the string

    // Load the unmanaged DLL
    HMODULE hModule = LoadLibrary(L"User.dll");
    if (!hModule) {
        std::cerr << "Failed to load User.dll" << std::endl;
        delete[] nativeUsername;
        delete[] nativePassword;
        return JNI_FALSE;
    }

    // Get the function pointer for the unmanaged function
    UserLoginFunc userLogin = (UserLoginFunc)GetProcAddress(hModule, "userLogin");
    if (!userLogin) {
        std::cerr << "Failed to find userLogin function in User.dll" << std::endl;
        FreeLibrary(hModule);
        delete[] nativeUsername;
        delete[] nativePassword;
        return JNI_FALSE;
    }

    // Call the unmanaged function
    bool result = userLogin(id, nativeUsername, nativePassword);

    // Clean up
    FreeLibrary(hModule);
    delete[] nativeUsername;
    delete[] nativePassword;

    // Return the result as a jboolean
    return result ? JNI_TRUE : JNI_FALSE;
}
```

---

### 3. **Compile the JNI Code**
You need to compile the C/C++ code into a shared library (DLL) that Java can load. Use a compiler like `gcc` (MinGW on Windows) or Visual Studio.

For example, using `gcc` on Windows:
```bash
