        // Create an instance of MyDate
        MyDate myDate = MyDate.builder()
                .date(LocalDate.of(2013, 5, 31))
                .build();

        // Serialize to JSON
        String json = mapper.writeValueAsString(myDate);
        System.out.println(json);
    }
}
```

