        Duration elapsedDuration = Duration.between(startTime, currentTime);

        // Compare the elapsed duration with activeAfterSecond
        if (elapsedDuration.compareTo(activeAfterSecond) >= 0) {
            System.out.println("The current time has passed the active duration.");
        } else {
            System.out.println("The current time has not yet passed the active duration.");
        }
    }
}
